class Solution:
    def longestSubsequence(self, s, k):
        zeros = s.count('0')
        ones_positions = []
        n = len(s)
        for i in range(n - 1, -1, -1):
            if s[i] == '1':
                ones_positions.append(n - 1 - i)
        ones_positions.sort()
        value = 0
        kept = 0
        for bit in ones_positions:
            add = 1 << bit
            if value + add <= k:
                value += add
                kept += 1
            else:
                break
        return zeros + kept

