class Solution:
    def longestSubsequence(self, s, k):
        total = 0
        kept_ones = 0
        value = 0
        n = len(s)
        for idx, ch in enumerate(reversed(s)):
            if ch == '0':
                total += 1
            else:
                if idx <= 30 and value + (1 << idx) <= k:
                    value += (1 << idx)
                    kept_ones += 1
        return total + kept_ones

