var longestSubsequence = function(s, k) {
    let total = 0;
    let keptOnes = 0;
    let value = 0;
    const n = s.length;
    for (let idx = 0; idx < n; idx++) {
        const ch = s[n - 1 - idx];
        if (ch === '0') {
            total++;
        } else if (idx <= 30 && value + (1 << idx) <= k) {
            value += (1 << idx);
            keptOnes++;
        }
    }
    return total + keptOnes;
};
